/**
 * Compute the set of tool logical-ids called by any step in the flow,
 * preserving registry order. Used by the renderer to auto-derive the
 * Claude `allowed-tools` frontmatter list.
 */
export function collectCalledToolIds(flow) {
    const called = new Set();
    for (const phase of flow.phases) {
        for (const step of phase.steps) {
            for (const id of step.toolCalls ?? []) {
                called.add(id);
            }
        }
    }
    return Object.keys(flow.tools).filter((id) => called.has(id));
}
/**
 * Resolve the next step(s) reachable from `step` when invoked in `mode`.
 * Returns an array because branch/loop kinds have multiple outgoing edges.
 *
 * For action/reference/parallel with `byMode` next, returns the per-mode
 * target. With a linear next, returns it for every mode. Branch and loop
 * kinds aren't mode-discriminating so they return all outgoing edges.
 */
export function nextRefsForMode(step, mode) {
    switch (step.kind) {
        case "action":
        case "reference":
        case "parallel":
            if (step.next === null || typeof step.next === "string") {
                return [step.next];
            }
            // byMode: missing entry = step is a dead end in that mode
            return [step.next.byMode[mode] ?? null];
        case "branch":
            return step.branches.map((b) => {
                if (b.next === null || typeof b.next === "string") {
                    return b.next;
                }
                return b.next.byMode[mode] ?? null;
            });
        case "loop":
            return [step.backTo, step.onExit];
    }
}
/**
 * Set of step ids reachable in any mode for the given target. The renderer
 * uses this as the visibility filter — a step renders iff it's reachable in
 * the current target. Replaces the hand-maintained `onlyTargets` flag.
 */
export function computeReachableSteps(flow, target) {
    return new Set(computeModesPerStep(flow, target).keys());
}
/**
 * For each step in the flow, the set of modes it is reachable in for a given
 * target. Used by the renderer to emit "skip this step if mode is X" prose
 * without the author having to hand-maintain a `modes` field.
 */
export function computeModesPerStep(flow, target) {
    const result = new Map();
    const stepById = new Map();
    for (const phase of flow.phases) {
        for (const step of phase.steps) {
            stepById.set(`${phase.id}/${step.id}`, step);
        }
    }
    for (const [mode, entry] of Object.entries(flow.entries)) {
        const start = resolvePerTarget(entry, target);
        if (start === undefined) {
            continue;
        }
        const queue = [start];
        const seen = new Set();
        while (queue.length > 0) {
            const id = queue.shift();
            if (id === undefined || seen.has(id)) {
                continue;
            }
            seen.add(id);
            const set = result.get(id) ?? new Set();
            set.add(mode);
            result.set(id, set);
            const step = stepById.get(id);
            if (step === undefined) {
                continue;
            }
            for (const n of nextRefsForMode(step, mode)) {
                if (n !== null) {
                    queue.push(n);
                }
            }
        }
    }
    return result;
}
/**
 * Diagram edge label for a branch entry. Derived from `option` when present,
 * otherwise reads `when` directly.
 */
export function branchLabel(branch) {
    if (branch.option !== undefined) {
        return `${branch.option.letter} — ${branch.option.label}`;
    }
    if (branch.when !== undefined) {
        return branch.when;
    }
    return "(unlabeled branch)";
}
